mapper.select:
select distinct b.id, b.language, b.name, b.author, b.description, b.total_price, b.words_price, b.chapter_price, b.free_chapters, b.cover, b.status, b.online_status, b.is_baoyue, b.is_hot, b.is_new, b.is_limited_free, b.is_greatest, b.is_god, b.total_words, b.total_chapters, b.total_views, b.total_favors, b.score, b.create_by, b.create_time, b.update_by, b.update_time, b.remark, c.name as category_name from t_book_info b left join t_book_category bc on b.id = bc.book_id left join t_category c on bc.category_id = c.id
b.deleted_at is null
AND b.name like concat('%', #{name}, '%')
AND b.author like concat('%', #{author}, '%')
AND b.status = #{status}
AND b.online_status = #{onlineStatus}
AND bc.category_id = #{categoryId}
and date_format(b.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
and date_format(b.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
order by b.id desc
